tests:
def test_n_4_count():
    result = solve_n_queens(4)
    assert len(result) == 2

def test_diagonals_n4():
    result = solve_n_queens(4)
    for board in result:
        positions = [(r, row.index('Q')) for r, row in enumerate(board)]
        for i in range(len(positions)):
            for j in range(i+1, len(positions)):
                r1, c1 = positions[i]
                r2, c2 = positions[j]
                assert abs(r1-r2) != abs(c1-c2)
